(async () => {
  const canvas = document.createElement('canvas')
  canvas.width = window.innerWidth * devicePixelRatio
  canvas.height = window.innerHeight * devicePixelRatio
  const ctx = canvas.getContext('2d')
  ctx.scale(devicePixelRatio, devicePixelRatio)
  ctx.fillStyle = getComputedStyle(document.body).backgroundColor || '#fff'
  ctx.fillRect(0, 0, window.innerWidth, window.innerHeight)
  ctx.fillStyle = '#000'
  ctx.font = '20px sans-serif'
  ctx.fillText('Full-page screenshot capture is not available from plain browser JS in this runtime.', 20, 40)
  const dataUrl = canvas.toDataURL('image/png')
  const a = document.createElement('a')
  a.href = dataUrl
  a.download = `screenshot-${Date.now()}.png`
  a.click()
  return 'Triggered a downloadable PNG placeholder, but true page screenshot capture is not available from plain browser JS here.'
})()

